#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=400005;
int n,m;
ll tr[N],tr2[N],tag[N];
void push_down(int u,int l,int r) 
{
	int mid=(l+r)/2;
	ll num=tag[u];
	tr2[u*2]+=(num*num*(mid-l+1)+num*2*tr[u*2]);
	tr2[u*2+1]+=(num*num*(r-mid)+num*2*tr[u*2+1]);
	tr[u*2]+=((mid-l+1)*num);
	tr[u*2+1]+=((r-mid)*num);
	tag[u*2]+=tag[u];
	tag[u*2+1]+=tag[u];
	tag[u]=0;
}
void add(int u,int l,int r,int x,int y,int k)
{
	if(l>y||r<x) return ;
	if(l>=x&&r<=y)
	{
		tr2[u]+=(ll)(k*k*(r-l+1)+k*2*tr[u]);
		tr[u]+=(ll)(k*(r-l+1));
		tag[u]+=k;
		return;
	}
	int mid=(l+r)>>1;
	push_down(u,l,r);
	add(u*2,l,mid,x,y,k);
	add(u*2+1,mid+1,r,x,y,k);
	tr[u]=tr[u*2]+tr[u*2+1];
	tr2[u]=tr2[u*2]+tr2[u*2+1];
}
ll sum(int u,int l,int r,int x,int y)
{
	if(l>y||r<x) return 0;
	if(l>=x&&r<=y) return tr[u];
	push_down(u,l,r);
	int mid=(l+r)>>1;
	return sum(u*2,l,mid,x,y)+sum(u*2+1,mid+1,r,x,y);
}
ll sum2(int u,int l,int r,int x,int y)
{
	if(l>y||r<x) return 0;
	if(l>=x&&r<=y) return tr2[u];
	push_down(u,l,r);
	int mid=(l+r)>>1;
	return sum2(u*2,l,mid,x,y)+sum2(u*2+1,mid+1,r,x,y);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		int x;
		cin>>x;
		add(1,1,n,i,i,x);
	}
	while(m--) 
	{
		int op,l,r,d;
		cin>>op>>l>>r;
		if(op==1)
		{
			cin>>d;
			add(1,1,n,l,r,d);
		}
		else if(op==2)
		{
			ll p=sum(1,1,n,l,r),q=r-l+1;
			ll gc=__gcd(p,q);
			p/=gc;
			q/=gc;
			cout<<p<<"/"<<q<<'\n';
		}
		else
		{
			ll sum1=sum(1,1,n,l,r);
			ll s2=sum2(1,1,n,l,r);
			ll len=r-l+1;
//			int p=sum2(1,1,n,l,r)/len+sum1/len*sum1,q=len;
            // 方差 = (s2*len - s1*s1) / (len*len)
            ll p=s2*len - sum1*sum1;
            ll q=len*len;
				ll gc=__gcd(p,q);
				p/=gc;
				q/=gc;
				cout<<p<<"/"<<q<<'\n';

		}
	}
	return 0;
}
